    if x <= 0:
        return False

    # A fraction in lowest terms is a terminating decimal iff
    # the denominator has only factors of 2 and 5

    # For 1/(x^2 + x) = 1/(x(x+1)), we need to reduce to lowest terms
    # and check if denominator has only factors 2 and 5

    def only_factors_2_and_5(n):
        """Check if n has only 2 and 5 as prime factors"""
        if n <= 0:
            return False
        while n % 2 == 0:
            n //= 2
        while n % 5 == 0:
            n //= 5
        return n == 1

    def gcd(a, b):
        while b:
            a, b = b, a % b
        return a

    # Check if 1/(x(x+1)) is terminating
    denominator = x * (x + 1)
    numerator = 1

    # Reduce to lowest terms
    g = gcd(numerator, denominator)
    reduced_denom = denominator // g

    # Check if reduced denominator has only factors 2 and 5
    is_terminating = only_factors_2_and_5(reduced_denom)

    if not is_terminating:
        return False

    # Now find all positive integers that make 1/(x^2+x) terminating
    # and check if x is the second smallest
    valid_x = []
    for candidate in range(1, 10000):
        denom = candidate * (candidate + 1)
        g = gcd(1, denom)
        reduced = denom // g
        if only_factors_2_and_5(reduced):
            valid_x.append(candidate)

    if len(valid_x) < 2:
        return False

    return valid_x[1] == x

