    from math import gcd
    from functools import reduce

    # Factor 2025
    n = 2025

    # Find all divisors of 2025
    divisors = []
    for i in range(1, int(n**0.5) + 1):
        if n % i == 0:
            divisors.append(i)
            if i != n // i:
                divisors.append(n // i)
    divisors.sort()

    # Function to compute LCM of a list
    def lcm(a, b):
        return a * b // gcd(a, b)

    def lcm_of_list(lst):
        return reduce(lcm, lst)

    # Count nonempty subsets with LCM = 2025
    count = 0
    total_subsets = 2 ** len(divisors) - 1  # exclude empty set

    # Enumerate all nonempty subsets
    for mask in range(1, 2 ** len(divisors)):
        subset = [divisors[i] for i in range(len(divisors)) if mask & (1 << i)]
        if lcm_of_list(subset) == n:
            count += 1

    # Compute probability as reduced fraction
    g = gcd(count, total_subsets)
    m = count // g
    n_frac = total_subsets // g

    # Check if m and n are coprime
    if gcd(m, n_frac) != 1:
        return False

    result = m + n_frac

    try:
